#include <stdio.h>

int main(void) {
    char s[200];
    char c;
    scanf("%199s", s);
    scanf(" %c", &c);
    // ここにコードを書いてください
    return 0;
}

hint:
文字列を 1 文字ずつ見て、`c` と一致したら数えます。`'\0'` が文字列の終わりです。

```c
int count = 0;
for (int i = 0; s[i] != '\0'; i++) {
    if (s[i] == c) count++;
}
printf("%d\n", count);
```

explanation:
## 解説

C の文字列は末尾に `'\0'`（ヌル文字）があります。先頭から `'\0'` の手前まで 1 文字ずつ調べ、`c` と一致した数を数えます。`scanf(" %c", &c)` の先頭の空白は、前の入力で残った改行を読み飛ばすためのものです。

```c
int count = 0;
for (int i = 0; s[i] != '\0'; i++) {
    if (s[i] == c) count++;
}
printf("%d\n", count);
```

answer_code:
#include <stdio.h>

int main(void) {
    char s[200];
    char c;
    scanf("%199s", s);
    scanf(" %c", &c);
    int count = 0;
    for (int i = 0; s[i] != '\0'; i++) {
        if (s[i] == c) count++;
    }
    printf("%d\n", count);
    return 0;
}
